import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react()],
})

import './App.css'

function App() {
  return (
    <div className="mms-app">
      <h1>MMS Demo Application</h1>
      <p>Metro Fleet Mileage Management System</p>
      <p className="mms-status">Ready for development</p>
    </div>
  )
}

export default App

