     1вҶ’/**
     2вҶ’ * MMS Store Types
     3вҶ’ *
     4вҶ’ * TypeScript interfaces for UI state management.
     5вҶ’ * These types align with the database schema but are optimized for frontend use.
     6вҶ’ *
     7вҶ’ * @see specs/006-user-interface.md Section 6.4
     8вҶ’ */
     9вҶ’
    10вҶ’// =============================================================================
    11вҶ’// Fleet Domain Types
    12вҶ’// =============================================================================
    13вҶ’
    14вҶ’export type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';
    15вҶ’export type PmStatus = 'SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'CANCELLED' | 'DEFERRED';
    16вҶ’export type TrackType = 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';
    17вҶ’export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';
    18вҶ’
    19вҶ’/** Train entity optimized for UI rendering */
    20вҶ’export interface Train {
    21вҶ’  id: string;
    22вҶ’  trainNumber: string;
    23вҶ’  fleetId: string;
    24вҶ’  fleetCode: string;
    25вҶ’  currentMileageKm: number;
    26вҶ’  targetMileageKm: number | null;
    27вҶ’  fitnessStatus: FitnessStatus;
    28вҶ’  fitnessNotes: string | null;
    29вҶ’  currentDepotId: string | null;
    30вҶ’  homeDepotId: string | null;
    31вҶ’  displayColor: string;
    32вҶ’  commissioningDate: string | null;
    33вҶ’  updatedAt: string;
    34вҶ’}
    35вҶ’
    36вҶ’/** Fleet entity */
    37вҶ’export interface Fleet {
    38вҶ’  id: string;
    39вҶ’  code: string;
    40вҶ’  name: string;
    41вҶ’  manufacturer: string | null;
    42вҶ’  carsPerTrain: number;
    43вҶ’  baseDepotId: string | null;
    44вҶ’  displayColor: string;
    45вҶ’}
    46вҶ’
    47вҶ’/** Depot entity */
    48вҶ’export interface Depot {
    49вҶ’  id: string;
    50вҶ’  code: string;
    51вҶ’  name: string;
    52вҶ’  timezone: string;
    53вҶ’  latitude: number | null;
    54вҶ’  longitude: number | null;
    55вҶ’}
    56вҶ’
    57вҶ’/** Route entity */
    58вҶ’export interface Route {
    59вҶ’  id: string;
    60вҶ’  routeCode: string;
    61вҶ’  name: string;
    62вҶ’  expectedKmPerDay: number;
    63вҶ’  requiredTrains: number;
    64вҶ’  allowedFleetIds: string[];
    65вҶ’}
    66вҶ’
    67вҶ’// =============================================================================
    68вҶ’// PM Schedule Types
    69вҶ’// =============================================================================
    70вҶ’
    71вҶ’/** PM type definition */
    72вҶ’export interface PmType {
    73вҶ’  id: string;
    74вҶ’  fleetId: string;
    75вҶ’  pmCode: string;
    76вҶ’  description: string | null;
    77вҶ’  intervalKm: number | null;
    78вҶ’  intervalMonths: number | null;
    79вҶ’  satisfiesCodes: string[];
    80вҶ’  estimatedHours: number;
    81вҶ’  trackType: TrackType;
    82вҶ’}
    83вҶ’
    84вҶ’/** PM schedule entry for canvas rendering */
    85вҶ’export interface PmScheduleEntry {
    86вҶ’  id: string;
    87вҶ’  trainId: string;
    88вҶ’  trainNumber: string;
    89вҶ’  pmTypeId: string;
    90вҶ’  pmCode: string;
    91вҶ’  targetDate: string;
    92вҶ’  status: PmStatus;
    93вҶ’  constraintStart: string | null;
    94вҶ’  constraintEnd: string | null;
    95вҶ’  assignedTrackId: string | null;
    96вҶ’  isLocked: boolean;
    97вҶ’  lockedBy: string | null;
    98вҶ’  lockedAt: string | null;
    99вҶ’  scenarioId: string | null;
   100вҶ’  estimatedHours: number;
   101вҶ’  displayColor: string;
   102вҶ’}
   103вҶ’
   104вҶ’/** Drag-drop preview state */
   105вҶ’export interface DragState {
   106вҶ’  isDragging: boolean;
   107вҶ’  pmId: string | null;
   108вҶ’  sourceDate: string | null;
   109вҶ’  targetDate: string | null;
   110вҶ’  isValid: boolean;
   111вҶ’  validationMessage: string | null;
   112вҶ’  constraintViolations: ConstraintViolation[];
   113вҶ’}
   114вҶ’
   115вҶ’/** Constraint violation for drag preview */
   116вҶ’export interface ConstraintViolation {
   117вҶ’  type: 'COMPLIANCE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL' | 'MAXIMO_LOCK' | 'SERVICE_DEMAND';
   118вҶ’  severity: 'ERROR' | 'WARNING';
   119вҶ’  message: string;
   120вҶ’}
   121вҶ’
   122вҶ’// =============================================================================
   123вҶ’// Canvas Types
   124вҶ’// =============================================================================
   125вҶ’
   126вҶ’export type ZoomLevel = 'STRATEGIC' | 'TACTICAL_WIDE' | 'TACTICAL' | 'OPERATIONAL' | 'DETAIL';
   127вҶ’
   128вҶ’/** Canvas viewport state */
   129вҶ’export interface ViewportBounds {
   130вҶ’  startDate: string;
   131вҶ’  endDate: string;
   132вҶ’  trainIds: string[];
   133вҶ’}
   134вҶ’
   135вҶ’/** Canvas layer visibility */
   136вҶ’export interface LayerVisibility {
   137вҶ’  pmBlocks: boolean;
