   139вҶ’  manhourOverlay: boolean;
   140вҶ’  driftOverlay: boolean;
   141вҶ’  baselineShadow: boolean;
   142вҶ’}
   143вҶ’
   144вҶ’/** Canvas selection state */
   145вҶ’export interface CanvasSelection {
   146вҶ’  selectedPmIds: string[];
