   148вҶ’  isMultiSelect: boolean;
   149вҶ’}
   150вҶ’
   151вҶ’// =============================================================================
   152вҶ’// Scenario Types
   153вҶ’// =============================================================================
   154вҶ’
   155вҶ’export type ScenarioStatus = 'ACTIVE' | 'PROMOTED' | 'EXPIRED' | 'DISCARDED';
   156вҶ’export type DeltaType = 'PM_MOVE' | 'PM_ADD' | 'PM_REMOVE' | 'CAPACITY_CHANGE' | 'TRAIN_STATUS_CHANGE';
   157вҶ’
   158вҶ’/** Scenario entity */
   159вҶ’export interface Scenario {
   160вҶ’  id: string;
   161вҶ’  name: string;
   162вҶ’  description: string | null;
   163вҶ’  status: ScenarioStatus;
   164вҶ’  forkedFromBaselineId: string | null;
   165вҶ’  forkedFromScenarioId: string | null;
   166вҶ’  createdBy: string;
   167вҶ’  createdAt: string;
   168вҶ’  updatedAt: string;
   169вҶ’  expiresAt: string;
   170вҶ’  changeCount: number;
   171вҶ’}
   172вҶ’
   173вҶ’/** Scenario delta (change event) */
   174вҶ’export interface ScenarioDelta {
   175вҶ’  id: string;
   176вҶ’  scenarioId: string;
   177вҶ’  sequenceNum: number;
   178вҶ’  deltaType: DeltaType;
   179вҶ’  entityId: string;
