   181вҶ’  newValues: Record<string, unknown>;
   182вҶ’  createdAt: string;
   183вҶ’  createdBy: string;
   184вҶ’}
   185вҶ’
   186вҶ’// =============================================================================
   187вҶ’// UI State Types
   188вҶ’// =============================================================================
   189вҶ’
   190вҶ’/** Filter state for train list */
