     1вҶ’/**
     2вҶ’ * Batch Dispatch Utility
     3вҶ’ *
     4вҶ’ * Batches state updates for 60fps WebGL rendering.
     5вҶ’ * Uses requestAnimationFrame to coalesce rapid updates.
     6вҶ’ *
     7вҶ’ * @see specs/006-user-interface.md Section 6.4
     8вҶ’ */
     9вҶ’
    10вҶ’type DispatchFunction = () => void;
    11вҶ’
    12вҶ’// =============================================================================
    13вҶ’// Batch Queue
    14вҶ’// =============================================================================
    15вҶ’
    16вҶ’interface BatchQueue {
    17вҶ’  dispatches: DispatchFunction[];
    18вҶ’  rafId: number | null;
    19вҶ’  isProcessing: boolean;
    20вҶ’  frameTime: number;
    21вҶ’  maxBatchSize: number;
    22вҶ’}
    23вҶ’
    24вҶ’const queue: BatchQueue = {
    25вҶ’  dispatches: [],
    26вҶ’  rafId: null,
    27вҶ’  isProcessing: false,
    28вҶ’  frameTime: 1000 / 60, // ~16.67ms for 60fps
    29вҶ’  maxBatchSize: 100,
    30вҶ’};
    31вҶ’
    32вҶ’/**
    33вҶ’ * Process batched dispatches in a single animation frame
    34вҶ’ */
    35вҶ’function processBatch(): void {
    36вҶ’  if (queue.dispatches.length === 0) {
    37вҶ’    queue.isProcessing = false;
    38вҶ’    queue.rafId = null;
    39вҶ’    return;
    40вҶ’  }
    41вҶ’
    42вҶ’  queue.isProcessing = true;
    43вҶ’
    44вҶ’  // Take a snapshot of current dispatches
    45вҶ’  const batch = queue.dispatches.splice(0, queue.maxBatchSize);
    46вҶ’
    47вҶ’  // Execute all dispatches synchronously (React batches these automatically)
    48вҶ’  batch.forEach((dispatch) => {
    49вҶ’    try {
    50вҶ’      dispatch();
    51вҶ’    } catch (error) {
    52вҶ’      console.error('[BatchDispatch] Error in dispatch:', error);
    53вҶ’    }
    54вҶ’  });
    55вҶ’
    56вҶ’  // Schedule next frame if there are more dispatches
    57вҶ’  if (queue.dispatches.length > 0) {
    58вҶ’    queue.rafId = requestAnimationFrame(processBatch);
    59вҶ’  } else {
    60вҶ’    queue.isProcessing = false;
    61вҶ’    queue.rafId = null;
    62вҶ’  }
    63вҶ’}
    64вҶ’
    65вҶ’// =============================================================================
    66вҶ’// Public API
    67вҶ’// =============================================================================
    68вҶ’
    69вҶ’/**
    70вҶ’ * Queue a dispatch to be executed in the next animation frame.
    71вҶ’ * Multiple dispatches are batched together for optimal performance.
    72вҶ’ *
    73вҶ’ * @example
    74вҶ’ * ```tsx
    75вҶ’ * // In a high-frequency event handler (e.g., mouse move during drag)
    76вҶ’ * const handleDragMove = (x: number, y: number) => {
    77вҶ’ *   batchDispatch(() => {
    78вҶ’ *     canvasActions.setPan({ x, y });
    79вҶ’ *   });
    80вҶ’ * };
    81вҶ’ * ```
    82вҶ’ */
    83вҶ’export function batchDispatch(dispatch: DispatchFunction): void {
    84вҶ’  queue.dispatches.push(dispatch);
    85вҶ’
    86вҶ’  // Schedule processing if not already scheduled
    87вҶ’  if (queue.rafId === null && !queue.isProcessing) {
    88вҶ’    queue.rafId = requestAnimationFrame(processBatch);
    89вҶ’  }
    90вҶ’}
    91вҶ’
    92вҶ’/**
    93вҶ’ * Queue multiple dispatches to be executed together.
    94вҶ’ *
    95вҶ’ * @example
    96вҶ’ * ```tsx
    97вҶ’ * batchDispatches([
    98вҶ’ *   () => canvasActions.setZoom(10),
    99вҶ’ *   () => canvasActions.setPan({ x: 0, y: 0 }),
   100вҶ’ *   () => fleetActions.selectTrain('train-1'),
   101вҶ’ * ]);
   102вҶ’ * ```
   103вҶ’ */
   104вҶ’export function batchDispatches(dispatches: DispatchFunction[]): void {
   105вҶ’  queue.dispatches.push(...dispatches);
   106вҶ’
   107вҶ’  if (queue.rafId === null && !queue.isProcessing) {
   108вҶ’    queue.rafId = requestAnimationFrame(processBatch);
   109вҶ’  }
   110вҶ’}
   111вҶ’
   112вҶ’/**
   113вҶ’ * Immediately flush all pending batched dispatches.
   114вҶ’ * Use sparingly - primarily for testing or cleanup.
   115вҶ’ */
   116вҶ’export function flushBatch(): void {
   117вҶ’  if (queue.rafId !== null) {
   118вҶ’    cancelAnimationFrame(queue.rafId);
   119вҶ’    queue.rafId = null;
   120вҶ’  }
   121вҶ’
   122вҶ’  while (queue.dispatches.length > 0) {
   123вҶ’    const dispatch = queue.dispatches.shift();
   124вҶ’    if (dispatch) {
   125вҶ’      try {
   126вҶ’        dispatch();
   127вҶ’      } catch (error) {
   128вҶ’        console.error('[BatchDispatch] Error in flush:', error);
   129вҶ’      }
   130вҶ’    }
   131вҶ’  }
   132вҶ’
   133вҶ’  queue.isProcessing = false;
   134вҶ’}
   135вҶ’
   136вҶ’/**
   137вҶ’ * Cancel all pending batched dispatches.
   138вҶ’ * Does NOT execute them - use flushBatch for that.
   139вҶ’ */
   140вҶ’export function cancelBatch(): void {
   141вҶ’  if (queue.rafId !== null) {
   142вҶ’    cancelAnimationFrame(queue.rafId);
   143вҶ’    queue.rafId = null;
   144вҶ’  }
   145вҶ’
   146вҶ’  queue.dispatches = [];
   147вҶ’  queue.isProcessing = false;
   148вҶ’}
   149вҶ’
   150вҶ’/**
   151вҶ’ * Get the current batch queue status (for debugging)
   152вҶ’ */
   153вҶ’export function getBatchStatus(): {
   154вҶ’  pending: number;
   155вҶ’  isProcessing: boolean;
   156вҶ’  hasScheduled: boolean;
   157вҶ’} {
   158вҶ’  return {
   159вҶ’    pending: queue.dispatches.length,
   160вҶ’    isProcessing: queue.isProcessing,
   161вҶ’    hasScheduled: queue.rafId !== null,
   162вҶ’  };
   163вҶ’}
   164вҶ’
   165вҶ’// =============================================================================
   166вҶ’// Higher-Order Utilities
   167вҶ’// =============================================================================
   168вҶ’
   169вҶ’/**
   170вҶ’ * Creates a batched version of an action dispatcher.
   171вҶ’ * Useful for wrapping slice actions that are called frequently.
   172вҶ’ *
   173вҶ’ * @example
   174вҶ’ * ```tsx
   175вҶ’ * const batchedSetPan = createBatchedDispatcher(canvasActions.setPan);
   176вҶ’ *
   177вҶ’ * // In mouse move handler
   178вҶ’ * const handleMouseMove = (e: MouseEvent) => {
   179вҶ’ *   batchedSetPan({ x: e.clientX, y: e.clientY });
   180вҶ’ * };
   181вҶ’ * ```
   182вҶ’ */
   183вҶ’export function createBatchedDispatcher<T>(
   184вҶ’  action: (payload: T) => void
   185вҶ’): (payload: T) => void {
   186вҶ’  return (payload: T) => {
   187вҶ’    batchDispatch(() => action(payload));
   188вҶ’  };
   189вҶ’}
   190вҶ’
   191вҶ’/**
   192вҶ’ * Debounced batch dispatch - waits for a pause in rapid updates.
   193вҶ’ * Useful for search inputs or expensive operations.
   194вҶ’ *
   195вҶ’ * @param dispatch - The dispatch function to call
   196вҶ’ * @param delay - Debounce delay in milliseconds (default: 100ms)
   197вҶ’ */
   198вҶ’export function debouncedBatchDispatch(
   199вҶ’  dispatch: DispatchFunction,
   200вҶ’  delay = 100
   201вҶ’): () => void {
   202вҶ’  let timeoutId: ReturnType<typeof setTimeout> | null = null;
   203вҶ’
   204вҶ’  return () => {
   205вҶ’    if (timeoutId !== null) {
   206вҶ’      clearTimeout(timeoutId);
   207вҶ’    }
   208вҶ’
   209вҶ’    timeoutId = setTimeout(() => {
   210вҶ’      batchDispatch(dispatch);
   211вҶ’      timeoutId = null;
   212вҶ’    }, delay);
   213вҶ’  };
   214вҶ’}
   215вҶ’
   216вҶ’/**
   217вҶ’ * Throttled batch dispatch - ensures minimum time between dispatches.
   218вҶ’ * Useful for scroll handlers or resize events.
   219вҶ’ *
   220вҶ’ * @param dispatch - The dispatch function to call
   221вҶ’ * @param minInterval - Minimum interval between dispatches in milliseconds
   222вҶ’ */
   223вҶ’export function throttledBatchDispatch(
   224вҶ’  dispatch: DispatchFunction,
   225вҶ’  minInterval: number
   226вҶ’): () => void {
   227вҶ’  let lastDispatch = 0;
   228вҶ’  let pendingDispatch: ReturnType<typeof setTimeout> | null = null;
   229вҶ’
   230вҶ’  return () => {
   231вҶ’    const now = Date.now();
   232вҶ’    const elapsed = now - lastDispatch;
   233вҶ’
   234вҶ’    if (elapsed >= minInterval) {
   235вҶ’      lastDispatch = now;
   236вҶ’      batchDispatch(dispatch);
   237вҶ’    } else if (pendingDispatch === null) {
   238вҶ’      pendingDispatch = setTimeout(() => {
   239вҶ’        lastDispatch = Date.now();
   240вҶ’        batchDispatch(dispatch);
   241вҶ’        pendingDispatch = null;
   242вҶ’      }, minInterval - elapsed);
   243вҶ’    }
   244вҶ’  };
   245вҶ’}
   246вҶ’
   247вҶ’// =============================================================================
   248вҶ’// React Hook Utilities
   249вҶ’// =============================================================================
   250вҶ’
   251вҶ’/**
   252вҶ’ * Creates a callback that batches dispatches from pointer events.
   253вҶ’ * Optimized for drag operations on the canvas.
   254вҶ’ *
   255вҶ’ * @example
   256вҶ’ * ```tsx
   257вҶ’ * const onPointerMove = createPointerMoveHandler((x, y) => {
   258вҶ’ *   canvasActions.setPan({ x, y });
   259вҶ’ * });
   260вҶ’ *
   261вҶ’ * <canvas onPointerMove={onPointerMove} />
   262вҶ’ * ```
   263вҶ’ */
   264вҶ’export function createPointerMoveHandler(
   265вҶ’  handler: (x: number, y: number, event: PointerEvent) => void
   266вҶ’): (event: PointerEvent) => void {
   267вҶ’  return (event: PointerEvent) => {
   268вҶ’    batchDispatch(() => handler(event.clientX, event.clientY, event));
   269вҶ’  };
   270вҶ’}
   271вҶ’
   272вҶ’/**
   273вҶ’ * Creates a callback that batches dispatches from wheel events.
   274вҶ’ * Optimized for zoom operations on the canvas.
   275вҶ’ *
   276вҶ’ * @example
   277вҶ’ * ```tsx
   278вҶ’ * const onWheel = createWheelHandler((deltaY, x, y) => {
   279вҶ’ *   const zoomFactor = deltaY > 0 ? 0.9 : 1.1;
   280вҶ’ *   canvasActions.zoomIn(zoomFactor);
   281вҶ’ * });
   282вҶ’ *
   283вҶ’ * <canvas onWheel={onWheel} />
   284вҶ’ * ```
   285вҶ’ */
   286вҶ’export function createWheelHandler(
   287вҶ’  handler: (deltaY: number, x: number, y: number, event: WheelEvent) => void
   288вҶ’): (event: WheelEvent) => void {
   289вҶ’  return (event: WheelEvent) => {
   290вҶ’    event.preventDefault();
   291вҶ’    batchDispatch(() => handler(event.deltaY, event.clientX, event.clientY, event));
   292вҶ’  };
   293вҶ’}
   294вҶ’

