 */

type DispatchFunction = () => void;

// =============================================================================
// Batch Queue
// =============================================================================

interface BatchQueue {
  dispatches: DispatchFunction[];
  rafId: number | null;
  isProcessing: boolean;
  frameTime: number;
  maxBatchSize: number;
}

const queue: BatchQueue = {
  dispatches: [],
  rafId: null,
  isProcessing: false,
  frameTime: 1000 / 60, // ~16.67ms for 60fps
  maxBatchSize: 100,
};

/**
 * Process batched dispatches in a single animation frame
 */
function processBatch(): void {
  if (queue.dispatches.length === 0) {
    queue.isProcessing = false;
    queue.rafId = null;
    return;
  }

  queue.isProcessing = true;

  // Take a snapshot of current dispatches
  const batch = queue.dispatches.splice(0, queue.maxBatchSize);

  // Execute all dispatches synchronously (React batches these automatically)
  batch.forEach((dispatch) => {
    try {
      dispatch();
    } catch (error) {
      console.error('[BatchDispatch] Error in dispatch:', error);
    }
  });

  // Schedule next frame if there are more dispatches
  if (queue.dispatches.length > 0) {
    queue.rafId = requestAnimationFrame(processBatch);
  } else {
    queue.isProcessing = false;
    queue.rafId = null;
  }
}

// =============================================================================
// Public API
// =============================================================================

/**
 * Queue a dispatch to be executed in the next animation frame.
 * Multiple dispatches are batched together for optimal performance.
 *
 * @example
 * ```tsx
 * // In a high-frequency event handler (e.g., mouse move during drag)
 * const handleDragMove = (x: number, y: number) => {
 *   batchDispatch(() => {
 *     canvasActions.setPan({ x, y });
 *   });
 * };
 * ```
 */
export function batchDispatch(dispatch: DispatchFunction): void {
  queue.dispatches.push(dispatch);

  // Schedule processing if not already scheduled
  if (queue.rafId === null && !queue.isProcessing) {
    queue.rafId = requestAnimationFrame(processBatch);
  }
}

/**
 * Queue multiple dispatches to be executed together.
 *
 * @example
 * ```tsx
 * batchDispatches([
 *   () => canvasActions.setZoom(10),
 *   () => canvasActions.setPan({ x: 0, y: 0 }),
 *   () => fleetActions.selectTrain('train-1'),
 * ]);
 * ```
 */
export function batchDispatches(dispatches: DispatchFunction[]): void {
  queue.dispatches.push(...dispatches);

  if (queue.rafId === null && !queue.isProcessing) {
    queue.rafId = requestAnimationFrame(processBatch);
  }
}

/**
 * Immediately flush all pending batched dispatches.
 * Use sparingly - primarily for testing or cleanup.
 */
export function flushBatch(): void {
  if (queue.rafId !== null) {
    cancelAnimationFrame(queue.rafId);
    queue.rafId = null;
  }

  while (queue.dispatches.length > 0) {
    const dispatch = queue.dispatches.shift();
    if (dispatch) {
      try {
        dispatch();
      } catch (error) {
        console.error('[BatchDispatch] Error in flush:', error);
      }
    }
  }

  queue.isProcessing = false;
}

/**
 * Cancel all pending batched dispatches.
 * Does NOT execute them - use flushBatch for that.
 */
export function cancelBatch(): void {
  if (queue.rafId !== null) {
    cancelAnimationFrame(queue.rafId);
    queue.rafId = null;
  }

  queue.dispatches = [];
  queue.isProcessing = false;
}

/**
 * Get the current batch queue status (for debugging)
 */
export function getBatchStatus(): {
  pending: number;
  isProcessing: boolean;
  hasScheduled: boolean;
} {
  return {
    pending: queue.dispatches.length,
    isProcessing: queue.isProcessing,
    hasScheduled: queue.rafId !== null,
  };
}

// =============================================================================
// Higher-Order Utilities
// =============================================================================

/**
 * Creates a batched version of an action dispatcher.
 * Useful for wrapping slice actions that are called frequently.
 *
 * @example
 * ```tsx
 * const batchedSetPan = createBatchedDispatcher(canvasActions.setPan);
 *
 * // In mouse move handler
 * const handleMouseMove = (e: MouseEvent) => {
 *   batchedSetPan({ x: e.clientX, y: e.clientY });
 * };
 * ```
 */
export function createBatchedDispatcher<T>(
  action: (payload: T) => void
): (payload: T) => void {
  return (payload: T) => {
    batchDispatch(() => action(payload));
  };
}

/**
 * Debounced batch dispatch - waits for a pause in rapid updates.
 * Useful for search inputs or expensive operations.
 *
 * @param dispatch - The dispatch function to call
 * @param delay - Debounce delay in milliseconds (default: 100ms)
 */
export function debouncedBatchDispatch(
  dispatch: DispatchFunction,
  delay = 100
): () => void {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  return () => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
    }

    timeoutId = setTimeout(() => {
      batchDispatch(dispatch);
      timeoutId = null;
    }, delay);
  };
}

/**
 * Throttled batch dispatch - ensures minimum time between dispatches.
 * Useful for scroll handlers or resize events.
 *
 * @param dispatch - The dispatch function to call
 * @param minInterval - Minimum interval between dispatches in milliseconds
 */
export function throttledBatchDispatch(
  dispatch: DispatchFunction,
  minInterval: number
): () => void {
  let lastDispatch = 0;
  let pendingDispatch: ReturnType<typeof setTimeout> | null = null;

  return () => {
    const now = Date.now();
    const elapsed = now - lastDispatch;

    if (elapsed >= minInterval) {
      lastDispatch = now;
      batchDispatch(dispatch);
    } else if (pendingDispatch === null) {
      pendingDispatch = setTimeout(() => {
        lastDispatch = Date.now();
        batchDispatch(dispatch);
        pendingDispatch = null;
      }, minInterval - elapsed);
    }
  };
}

// =============================================================================
// React Hook Utilities
// =============================================================================

/**
 * Creates a callback that batches dispatches from pointer events.
 * Optimized for drag operations on the canvas.
 *
 * @example
 * ```tsx
 * const onPointerMove = createPointerMoveHandler((x, y) => {
 *   canvasActions.setPan({ x, y });
 * });
 *
 * <canvas onPointerMove={onPointerMove} />
 * ```
 */
export function createPointerMoveHandler(
  handler: (x: number, y: number, event: PointerEvent) => void
): (event: PointerEvent) => void {
  return (event: PointerEvent) => {
    batchDispatch(() => handler(event.clientX, event.clientY, event));
  };
}

/**
 * Creates a callback that batches dispatches from wheel events.
 * Optimized for zoom operations on the canvas.
 *
 * @example
 * ```tsx
 * const onWheel = createWheelHandler((deltaY, x, y) => {
 *   const zoomFactor = deltaY > 0 ? 0.9 : 1.1;
 *   canvasActions.zoomIn(zoomFactor);
 * });
 *
 * <canvas onWheel={onWheel} />
 * ```
 */
export function createWheelHandler(
  handler: (deltaY: number, x: number, y: number, event: WheelEvent) => void
): (event: WheelEvent) => void {
  return (event: WheelEvent) => {
    event.preventDefault();
    batchDispatch(() => handler(event.deltaY, event.clientX, event.clientY, event));
  };
}

