/**
 * Scenario Slice
 *
 * State management for what-if scenarios and comparison views.
 * Supports event-sourced delta tracking per spec 004.11.
 *
 * @see specs/006-user-interface.md Section 6.7
 */

import { createSlice, createAsyncSlice } from '@belt/tools';
import type {
  Scenario,
  ScenarioDelta,
  ScenarioStatus,
  DeltaType,
  Baseline,
  DriftAnalysis,
} from '../types';

// =============================================================================
// Scenario Slice State
// =============================================================================

export interface ScenarioSliceState {
  scenarios: Scenario[];
  activeScenarioId: string | null;
  activeDeltas: ScenarioDelta[];
  isComparing: boolean;
  comparisonScenarioId: string | null;
  comparisonBaselineId: string | null;
  baselines: Baseline[];
  activeBaselineId: string | null;
  driftAnalysis: DriftAnalysis[];
  isCreating: boolean;
  createError: string | null;
  isPromoting: boolean;
  promotionError: string | null;
  [key: string]: unknown;
}

const initialScenarioState: ScenarioSliceState = {
  scenarios: [],
  activeScenarioId: null,
  activeDeltas: [],
  isComparing: false,
  comparisonScenarioId: null,
  comparisonBaselineId: null,
  baselines: [],
  activeBaselineId: null,
  driftAnalysis: [],
  isCreating: false,
  createError: null,
  isPromoting: false,
  promotionError: null,
};

export const scenarioSlice = createSlice({
  id: 'scenario',
  initial: initialScenarioState,
  cache: { policy: 'session' },
  reducers: {
    // Scenarios
    setScenarios: (s, scenarios: Scenario[]) => {
      const state = s as ScenarioSliceState;
      state.scenarios = scenarios;
    },

    addScenario: (s, scenario: Scenario) => {
      const state = s as ScenarioSliceState;
      state.scenarios.push(scenario);
    },

    updateScenario: (s, scenario: Partial<Scenario> & { id: string }) => {
      const state = s as ScenarioSliceState;
      const index = state.scenarios.findIndex((sc) => sc.id === scenario.id);
      if (index !== -1) {
        state.scenarios[index] = { ...state.scenarios[index], ...scenario };
      }
    },

    removeScenario: (s, scenarioId: string) => {
      const state = s as ScenarioSliceState;
      state.scenarios = state.scenarios.filter((sc) => sc.id !== scenarioId);
      if (state.activeScenarioId === scenarioId) {
        state.activeScenarioId = null;
        state.activeDeltas = [];
      }
      if (state.comparisonScenarioId === scenarioId) {
        state.comparisonScenarioId = null;
        state.isComparing = false;
      }
    },

    updateScenarioStatus: (s, payload: { scenarioId: string; status: ScenarioStatus }) => {
      const state = s as ScenarioSliceState;
      const scenario = state.scenarios.find((sc) => sc.id === payload.scenarioId);
      if (scenario) {
        scenario.status = payload.status;
      }
    },

/**
 * UI Slice
 *
 * State management for global UI state: toasts, modals, loading, errors.
 *
 * @see specs/006-user-interface.md Section 6.8
 */

import { createSlice } from '@belt/tools';
import type { Toast, ModalState, LoadingState, ErrorState, OptimizerJob } from '../types';

// =============================================================================
// UI Slice State
// =============================================================================

export interface UiSliceState {
  // Toast notifications
  toasts: Toast[];
  maxToasts: number;

  // Modal state
  modal: ModalState;

  // Loading indicators
  loading: LoadingState;

  // Global error state
  error: ErrorState;

  // Sidebar collapsed
  sidebarCollapsed: boolean;

  // Help panel open
  helpPanelOpen: boolean;

  // Keyboard shortcuts enabled
  shortcutsEnabled: boolean;

  // Theme
  theme: 'light' | 'dark' | 'system';

  // Optimizer jobs tracking
  optimizerJobs: OptimizerJob[];
  activeJobId: string | null;

  // Connection status
  isOnline: boolean;
  websocketConnected: boolean;

  // Sync status
  lastSyncAt: number | null;
  syncInProgress: boolean;

  // Index signature for MachineState compatibility
  [key: string]: unknown;
}

const initialUiState: UiSliceState = {
  toasts: [],
  maxToasts: 5,
  modal: {
    isOpen: false,
    type: null,
    data: null,
  },
  loading: {
    trains: false,
    pmSchedule: false,
    canvas: false,
    optimizer: false,
  },
  error: {
    message: null,
    code: null,
    details: null,
    timestamp: null,
  },
  sidebarCollapsed: false,
  helpPanelOpen: false,
  shortcutsEnabled: true,
  theme: 'system',
  optimizerJobs: [],
  activeJobId: null,
  isOnline: true,
  websocketConnected: false,
  lastSyncAt: null,
  syncInProgress: false,
};

let toastIdCounter = 0;

export const uiSlice = createSlice({
  id: 'ui',
  initial: initialUiState,
  cache: { policy: 'session' },
  reducers: {
    // ==========================================================================
    // Toast Notifications
    // ==========================================================================
